// All known player names for a team — full squad if available, else key players.
export function playersOf(id) {
  const d = DETAILS[id] || {};
  const squad = (d.squad || []).map(row => Array.isArray(row) ? row[1] : row).filter(Boolean);
  if (squad.length) return squad;
  return (d.keyPlayers || []);
}
